parameters.jsCode:
const output = $input.first().json.output;

// Handle array of questions from agent
if (Array.isArray(output)) {
  // Return each question as a separate item for downstream processing
  return output.map(question => ({ json: question }));
}
// If no valid output, skip
return [];

// The vector store outputs the documents it just processed
const insertedDocuments = $input.all();

console.log(`Vector store inserted ${insertedDocuments.length} chunks`);

// Extract chunks
const chunks = insertedDocuments.map((doc, index) => {
  // The structure depends on what the vector store returns
  // Usually it's the original document data
  return {
    id: doc.json.id || `chunk_${index}`,
    content: doc.json.content || doc.json.pageContent || doc.json.text,
    metadata: doc.json.metadata || {}
  };
});

// Create batches
const BATCH_SIZE = 5;
const batches = [];

for (let i = 0; i < chunks.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      batch_number: Math.floor(i / BATCH_SIZE) + 1,
      chunks: chunks.slice(i, i + BATCH_SIZE)
    }
  });
}

console.log(`Created ${batches.length} batches`);
return batches;
